import type React from 'react';
import { act, renderHook } from '@testing-library/react';
import { beforeEach, describe, expect, it, vi } from 'vitest';
import { useFilterController } from '../../../../src/webview/components/settingsPanel/filters/controller';
import { graphStore } from '../../../../src/webview/store/state';

const sentMessages: unknown[] = [];
vi.mock('../../../../src/webview/vscodeApi', () => ({
  postMessage: (message: unknown) => sentMessages.push(message),
  vscode: { getState: () => undefined, setState: vi.fn() },
}));

function setStoreState(overrides: Record<string, unknown> = {}) {
  graphStore.setState({
    filterPatterns: [],
    maxFiles: 500,
    pluginFilterPatterns: [],
    showOrphans: true,
    ...overrides,
  });
}

describe('filters controller', () => {
  beforeEach(() => {
    sentMessages.length = 0;
  });

  it('exposes the current filter state from the graph store', () => {
    setStoreState({
      filterPatterns: ['**/*.test.ts'],
      maxFiles: 250,
      pluginFilterPatterns: ['**/*.generated.ts'],
      showOrphans: false,
    });

    const { result } = renderHook(() => useFilterController());

    expect(result.current.filterPatterns).toEqual(['**/*.test.ts']);
    expect(result.current.maxFiles).toBe(250);
    expect(result.current.pluginFilterPatterns).toEqual(['**/*.generated.ts']);
    expect(result.current.showOrphans).toBe(false);
    expect(result.current.newFilterPattern).toBe('');
  });

  it('adds trimmed patterns and clears the draft', () => {
    setStoreState();
    const { result } = renderHook(() => useFilterController());

    act(() => {
      result.current.onPatternChange('  **/*.cache  ');
    });

    act(() => {
      result.current.onAddPattern();
    });

    expect(graphStore.getState().filterPatterns).toEqual(['**/*.cache']);
    expect(result.current.newFilterPattern).toBe('');
  });

  it('deletes patterns from the store and posts the updated list', () => {
    setStoreState({ filterPatterns: ['**/*.cache', '**/*.log'] });
    const { result } = renderHook(() => useFilterController());

    act(() => {
      result.current.onDeletePattern('**/*.cache');
    });

    expect(graphStore.getState().filterPatterns).toEqual(['**/*.log']);
    expect(sentMessages).toContainEqual({
      type: 'UPDATE_FILTER_PATTERNS',
      payload: { patterns: ['**/*.log'] },
    });
  });

  it('edits patterns in the store and posts the updated list', () => {
    setStoreState({ filterPatterns: ['**/*.cache', '**/*.log'] });
    const { result } = renderHook(() => useFilterController());

    act(() => {
      result.current.onEditPattern('**/*.cache', '**/*.tmp');
    });

    expect(graphStore.getState().filterPatterns).toEqual(['**/*.tmp', '**/*.log']);
    expect(sentMessages).toContainEqual({
      type: 'UPDATE_FILTER_PATTERNS',
      payload: { patterns: ['**/*.tmp', '**/*.log'] },
    });
  });

  it('decreases max files by one hundred and clamps at one', () => {
    setStoreState({ maxFiles: 50 });
    const { result } = renderHook(() => useFilterController());

    act(() => {
      result.current.onDecreaseMaxFiles();
    });

    expect(graphStore.getState().maxFiles).toBe(1);
    expect(sentMessages).toContainEqual({
      type: 'UPDATE_MAX_FILES',
      payload: { maxFiles: 1 },
    });
  });

  it('increases max files by one hundred', () => {
    setStoreState({ maxFiles: 500 });
    const { result } = renderHook(() => useFilterController());

    act(() => {
      result.current.onIncreaseMaxFiles();
    });

    expect(graphStore.getState().maxFiles).toBe(600);
    expect(sentMessages).toContainEqual({
      type: 'UPDATE_MAX_FILES',
      payload: { maxFiles: 600 },
    });
  });

  it('updates max files optimistically for valid input changes only', () => {
    setStoreState({ maxFiles: 500 });
    const { result } = renderHook(() => useFilterController());

    act(() => {
      result.current.onMaxFilesChange('275');
    });

    expect(graphStore.getState().maxFiles).toBe(275);

    act(() => {
      result.current.onMaxFilesChange('abc');
    });

    expect(graphStore.getState().maxFiles).toBe(275);
  });

  it('commits parsed max files on blur and falls back to one for invalid values', () => {
    setStoreState({ maxFiles: 500 });
    const { result } = renderHook(() => useFilterController());

    act(() => {
      result.current.onMaxFilesBlur('250');
    });

    expect(graphStore.getState().maxFiles).toBe(250);
    expect(sentMessages).toContainEqual({
      type: 'UPDATE_MAX_FILES',
      payload: { maxFiles: 250 },
    });

    sentMessages.length = 0;

    act(() => {
      result.current.onMaxFilesBlur('not-a-number');
    });

    expect(graphStore.getState().maxFiles).toBe(1);
    expect(sentMessages).toContainEqual({
      type: 'UPDATE_MAX_FILES',
      payload: { maxFiles: 1 },
    });
  });

  it('publishes max-file updates on enter', () => {
    setStoreState({ maxFiles: 500 });
    const { result } = renderHook(() => useFilterController());

    act(() => {
      result.current.onMaxFilesKeyDown({
        key: 'Enter',
        currentTarget: { value: '350' },
      } as React.KeyboardEvent<HTMLInputElement>);
    });

    expect(graphStore.getState().maxFiles).toBe(350);
    expect(sentMessages).toContainEqual({
      type: 'UPDATE_MAX_FILES',
      payload: { maxFiles: 350 },
    });
  });

  it('ignores non-enter key presses for max-file input commits', () => {
    setStoreState({ maxFiles: 500 });
    const { result } = renderHook(() => useFilterController());

    act(() => {
      result.current.onMaxFilesKeyDown({
        key: 'Escape',
        currentTarget: { value: '350' },
      } as React.KeyboardEvent<HTMLInputElement>);
    });

    expect(graphStore.getState().maxFiles).toBe(500);
    expect(sentMessages).toEqual([]);
  });

  it('updates orphan visibility and posts the new flag', () => {
    setStoreState({ showOrphans: true });
    const { result } = renderHook(() => useFilterController());

    act(() => {
      result.current.onShowOrphansChange(false);
    });

    expect(graphStore.getState().showOrphans).toBe(false);
    expect(sentMessages).toContainEqual({
      type: 'UPDATE_SHOW_ORPHANS',
      payload: { showOrphans: false },
    });
  });
});

import { describe, expect, it, vi } from 'vitest';
import {
  addFilterPattern,
  deleteFilterPattern,
  editFilterPattern,
} from '../../../../src/webview/components/settingsPanel/filters/patternActions';

const sentMessages: unknown[] = [];
vi.mock('../../../../src/webview/vscodeApi', () => ({
  postMessage: (message: unknown) => sentMessages.push(message),
  vscode: { getState: () => undefined, setState: vi.fn() },
}));

describe('filters patternActions', () => {
  it('adds normalized patterns and clears the draft value', () => {
    const setFilterPatterns = vi.fn();
    const setNewFilterPattern = vi.fn();

    addFilterPattern(
      ['**/*.tmp'],
      '  **/*.cache  ',
      setFilterPatterns,
      setNewFilterPattern
    );

    expect(setFilterPatterns).toHaveBeenCalledWith(['**/*.tmp', '**/*.cache']);
    expect(setNewFilterPattern).toHaveBeenCalledWith('');
    expect(sentMessages).toContainEqual({
      type: 'UPDATE_FILTER_PATTERNS',
      payload: { patterns: ['**/*.tmp', '**/*.cache'] },
    });
  });

  it('ignores invalid draft patterns', () => {
    const setFilterPatterns = vi.fn();
    const setNewFilterPattern = vi.fn();

    addFilterPattern([], '   ', setFilterPatterns, setNewFilterPattern);

    expect(setFilterPatterns).not.toHaveBeenCalled();
    expect(setNewFilterPattern).not.toHaveBeenCalled();
  });

  it('removes a pattern and emits the update', () => {
    const setFilterPatterns = vi.fn();

    deleteFilterPattern(['**/*.tmp', '**/*.cache'], '**/*.tmp', setFilterPatterns);

    expect(setFilterPatterns).toHaveBeenCalledWith(['**/*.cache']);
    expect(sentMessages).toContainEqual({
      type: 'UPDATE_FILTER_PATTERNS',
      payload: { patterns: ['**/*.cache'] },
    });
  });

  it('edits an existing pattern and emits the update', () => {
    const setFilterPatterns = vi.fn();

    editFilterPattern(
      ['**/*.tmp', '**/*.cache'],
      '**/*.tmp',
      '  **/*.log  ',
      setFilterPatterns,
    );

    expect(setFilterPatterns).toHaveBeenCalledWith(['**/*.log', '**/*.cache']);
    expect(sentMessages).toContainEqual({
      type: 'UPDATE_FILTER_PATTERNS',
      payload: { patterns: ['**/*.log', '**/*.cache'] },
    });
  });

  it('ignores invalid edited patterns', () => {
    const setFilterPatterns = vi.fn();

    editFilterPattern(
      ['**/*.tmp', '**/*.cache'],
      '**/*.tmp',
      '   ',
      setFilterPatterns,
    );

    expect(setFilterPatterns).not.toHaveBeenCalled();
  });

  it('skips edits that normalize back to the previous pattern', () => {
    const setFilterPatterns = vi.fn();

    editFilterPattern(
      ['**/*.tmp', '**/*.cache'],
      '**/*.tmp',
      '  **/*.tmp  ',
      setFilterPatterns,
    );

    expect(setFilterPatterns).not.toHaveBeenCalled();
  });
});

import { describe, expect, it } from 'vitest';
import {
  canAddFilterPattern,
  clampMaxFiles,
  decreaseMaxFiles,
  increaseMaxFiles,
  parseMaxFilesInput,
  shouldShowPluginFilterPatterns,
} from '../../../../src/webview/components/settingsPanel/filters/model';

describe('settingsPanel filter model', () => {
  it('only allows non-empty filter patterns after trimming', () => {
    expect(canAddFilterPattern('**/*.log')).toBe(true);
    expect(canAddFilterPattern('   ')).toBe(false);
  });

  it('clamps max files to at least one', () => {
    expect(clampMaxFiles(0)).toBe(1);
    expect(clampMaxFiles(250)).toBe(250);
  });

  it('parses numeric max-file inputs and rejects invalid values', () => {
    expect(parseMaxFilesInput('250')).toBe(250);
    expect(parseMaxFilesInput('abc')).toBeNull();
  });

  it('decreases max files in steps of one hundred without going below one', () => {
    expect(decreaseMaxFiles(500)).toBe(400);
    expect(decreaseMaxFiles(50)).toBe(1);
  });

  it('increases max files in steps of one hundred', () => {
    expect(increaseMaxFiles(500)).toBe(600);
  });

  it('shows plugin filter patterns only when defaults are present', () => {
    expect(shouldShowPluginFilterPatterns(['**/*.uid'])).toBe(true);
    expect(shouldShowPluginFilterPatterns([])).toBe(false);
  });
});

import { fireEvent, render, screen } from '@testing-library/react';
import { beforeEach, describe, expect, it, vi } from 'vitest';
import { FilterSection } from '../../../../src/webview/components/settingsPanel/filters/Section';
import { graphStore } from '../../../../src/webview/store/state';

const sentMessages: unknown[] = [];
vi.mock('../../../../src/webview/vscodeApi', () => ({
  postMessage: (message: unknown) => sentMessages.push(message),
  vscode: { getState: () => undefined, setState: vi.fn() },
}));

function setStoreState(overrides: Record<string, unknown> = {}) {
  graphStore.setState({
    filterPatterns: [],
    pluginFilterPatterns: [],
    showOrphans: true,
    maxFiles: 500,
    ...overrides,
  });
}

function renderSection(storeOverrides: Record<string, unknown> = {}) {
  setStoreState(storeOverrides);
  return render(<FilterSection />);
}

describe('FilterSection', () => {
  beforeEach(() => {
    sentMessages.length = 0;
  });

  it('starts with the add button disabled', () => {
    renderSection();

    expect(screen.getByRole('button', { name: /^Add$/i })).toBeDisabled();
  });

  it('renders existing filter patterns', () => {
    renderSection({ filterPatterns: ['**/*.test.ts', '**/*.spec.ts'] });

    expect(screen.getByDisplayValue('**/*.test.ts')).toBeInTheDocument();
    expect(screen.getByDisplayValue('**/*.spec.ts')).toBeInTheDocument();
  });

  it('shows an empty-state message when no custom filter patterns exist', () => {
    renderSection({ filterPatterns: [] });

    expect(screen.getByText('No patterns.')).toBeInTheDocument();
  });

  it('renders plugin defaults when plugin filter patterns are present', () => {
    renderSection({ pluginFilterPatterns: ['**/*.uid'] });

    expect(screen.getByText('Plugin defaults (read-only)')).toBeInTheDocument();
    expect(screen.getByText('**/*.uid')).toBeInTheDocument();
  });

  it('adds a filter pattern on button click', () => {
    renderSection();

    const input = screen.getByPlaceholderText('*.png');
    fireEvent.change(input, { target: { value: '**/*.log' } });
    fireEvent.click(screen.getByRole('button', { name: /^Add$/i }));

    expect(graphStore.getState().filterPatterns).toEqual(['**/*.log']);
    expect(input).toHaveValue('');
    expect(sentMessages).toContainEqual({
      type: 'UPDATE_FILTER_PATTERNS',
      payload: { patterns: ['**/*.log'] },
    });
  });

  it('adds a filter pattern on enter', () => {
    renderSection();

    const input = screen.getByPlaceholderText('*.png');
    fireEvent.change(input, { target: { value: '**/*.cache' } });
    fireEvent.keyDown(input, { key: 'Enter' });

    expect(graphStore.getState().filterPatterns).toEqual(['**/*.cache']);
  });

  it('disables the add button for whitespace-only input', () => {
    renderSection();

    fireEvent.change(screen.getByPlaceholderText('*.png'), {
      target: { value: '   ' },
    });

    expect(screen.getByRole('button', { name: /^Add$/i })).toBeDisabled();
  });

  it('does not add a whitespace-only filter pattern on enter', () => {
    renderSection();

    const input = screen.getByPlaceholderText('*.png');
    fireEvent.change(input, { target: { value: '   ' } });
    fireEvent.keyDown(input, { key: 'Enter' });

    expect(graphStore.getState().filterPatterns).toEqual([]);
    expect(sentMessages).toEqual([]);
  });

  it('removes a filter pattern', () => {
    renderSection({ filterPatterns: ['**/*.log', '**/*.tmp'] });

    fireEvent.click(screen.getAllByTitle('Delete pattern')[0]);

    expect(graphStore.getState().filterPatterns).toEqual(['**/*.tmp']);
    expect(sentMessages).toContainEqual({
      type: 'UPDATE_FILTER_PATTERNS',
      payload: { patterns: ['**/*.tmp'] },
    });
  });

  it('toggles orphan visibility', () => {
    renderSection({ showOrphans: true });

    fireEvent.click(screen.getByRole('switch'));

    expect(graphStore.getState().showOrphans).toBe(false);
    expect(sentMessages).toContainEqual({
      type: 'UPDATE_SHOW_ORPHANS',
      payload: { showOrphans: false },
    });
  });

  it('decreases max files and clamps at one', () => {
    renderSection({ maxFiles: 50 });

    fireEvent.click(screen.getByTitle('Decrease by 100'));

    expect(graphStore.getState().maxFiles).toBe(1);
    expect(sentMessages).toContainEqual({
      type: 'UPDATE_MAX_FILES',
      payload: { maxFiles: 1 },
    });
  });

  it('disables the decrease button at the minimum max-file value', () => {
    renderSection({ maxFiles: 1 });

    expect(screen.getByTitle('Decrease by 100')).toBeDisabled();
  });

  it('increases max files by one hundred', () => {
    renderSection({ maxFiles: 500 });

    fireEvent.click(screen.getByTitle('Increase by 100'));

    expect(graphStore.getState().maxFiles).toBe(600);
    expect(sentMessages).toContainEqual({
      type: 'UPDATE_MAX_FILES',
      payload: { maxFiles: 600 },
    });
  });

  it('commits max files on blur', () => {
    renderSection({ maxFiles: 500 });

    const input = screen.getByDisplayValue('500');
    fireEvent.change(input, { target: { value: '250' } });
    fireEvent.blur(input);

    expect(graphStore.getState().maxFiles).toBe(250);
    expect(sentMessages).toContainEqual({
      type: 'UPDATE_MAX_FILES',
      payload: { maxFiles: 250 },
    });
  });

  it('ignores non-numeric max-file input changes', () => {
    renderSection({ maxFiles: 500 });

    const input = screen.getByDisplayValue('500');
    fireEvent.change(input, { target: { value: 'abc' } });

    expect(graphStore.getState().maxFiles).toBe(500);
  });

  it('commits max files on enter', () => {
    renderSection({ maxFiles: 500 });

    const input = screen.getByDisplayValue('500');
    fireEvent.change(input, { target: { value: '350' } });
    fireEvent.keyDown(input, { key: 'Enter' });

    expect(graphStore.getState().maxFiles).toBe(350);
    expect(sentMessages).toContainEqual({
      type: 'UPDATE_MAX_FILES',
      payload: { maxFiles: 350 },
    });
  });

  it('does not commit max files for non-enter key presses', () => {
    renderSection({ maxFiles: 500 });

    const input = screen.getByDisplayValue('500');
    fireEvent.change(input, { target: { value: '350' } });
    fireEvent.keyDown(input, { key: 'Escape' });

    expect(sentMessages).toEqual([]);
  });
});
